import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"镜像行者—下属奇物","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者—下属奇物.md","filePath":"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者—下属奇物.md"}'),o={name:"4.资源分区/2.改造与功法/改造/2.社交类/镜像行者/镜像行者—下属奇物.md"};function _(b,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"镜像行者—下属奇物",tabindex:"-1"},[n("镜像行者—下属奇物 "),r("a",{class:"header-anchor",href:"#镜像行者—下属奇物","aria-label":'Permalink to "镜像行者—下属奇物"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),s('<h1 id="镜像行者—下属奇物-1" tabindex="-1">镜像行者—下属奇物 <a class="header-anchor" href="#镜像行者—下属奇物-1" aria-label="Permalink to &quot;镜像行者—下属奇物&quot;">​</a></h1><p>下属奇物</p><p>黑室<br> D+500<br> 无光之域</p><p>为镜像行者提供灵感视觉，</p><p>此外，每场影片结束时，若在本次影片中，镜像行者经过了至少一场同级别的战斗，那么倒影获得2点遮蔽防御。</p><p>当改造等级达到C级时，可以再次购买该奇物，此时会额外提供【法破】，并且影片结束时，倒影额外获得2点攻击检定上的加值。</p><p>十七边形<br> D+1000<br> 购买前提：持有唯一分形<br> 占据护符位<br> 这是一个曾经被认为不可被尺规作出的图像。<br> 同时升级【分形】和【递归】</p><p>【分形】：现在持有者具有【法破】，</p><p>【递归】：现在由【递归】效果带来的减值上限提升至操控属性*2点。</p><p>正七面体<br> C+2000<br> 占据戒指位<br> 购买前提：唯一分形等级达到C<br> 其的每一个面都是标准的正七面体，<br> 不要去测量它，不要去理解它。<br> 升级【分形】</p><p>现在镜像行者和倒影的攻击都转为使用强韧豁免对抗，</p><p>【分形】：现在同时为镜像行者和倒影提供他们持有武器时的效果，但是不提供武器伤害。</p><p>直线<br> C+2000<br> 占据戒指位<br> 购买前提：镜像行者的改造等级达到C<br> 向上无穷，向下无尽，<br> 限定空间，拘束时间。<br> 强化【递归】</p><p>现在镜像行者的攻击射程增加操控属性*1M，倒影的触及范围扩大6M，</p><p>【递归】：受到递归影响的敌人，其每次被攻击命中时，会受到1点不可豁免的纠缠异常点数，</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(o,[["render",_]]);export{f as __pageData,m as default};
